from seed import BigUnionZero, SeedApi

client = SeedApi(
    base_url="https://yourhost.com/path/to/api",
)
client.bigunion.update(
    request=BigUnionZero(
        value="value",
        type="normalSweet",
    ),
)

from seed import BigUnionZero, SeedApi

client = SeedApi(
    base_url="https://yourhost.com/path/to/api",
)
client.bigunion.update_many(
    request=[
        BigUnionZero(
            value="value",
            type="normalSweet",
        )
    ],
)

from seed import SeedApi, ShapeZero

client = SeedApi(
    base_url="https://yourhost.com/path/to/api",
)
client.union.update(
    request=ShapeZero(
        radius=1.1,
        type="circle",
    ),
)
